有一个新视频: {latest_video['title']}
链接: https://www.bilibili.com/video/{latest_video['bvid']}
更新时间：{created_datetime}
[CQ:image,file={video_pic}]" send_group_message(group_id, message) cursor.execute('UPDATE monitoring SET last_checked = ? WHERE group_id = ? AND qq_id = ? AND bilibili_uid = ?', (latest_timestamp, group_id, qq_id, uid)) conn.commit() conn.close() except : logging.info('wrong-update:', time.time()) async def main(send_group_message): while True: await check_updates(send_group_message) await asyncio.sleep(45) # 45秒检测一次 if __name__ == "__main__": from scripts.bilibili.bilibili import send_group_message asyncio.run(main(send_group_message))

